<script setup lang="ts">
import { computed, onMounted, reactive, ref, watch } from "vue";
import { ElMessage, ElMessageBox } from "element-plus";
import { api, type ApplicationItem, type TeamMemberItem, type TeamSummary } from "../api";
const props = defineProps<{ ownerUserId?: number | null; adminMode: boolean }>();
const teams = ref<TeamSummary[]>([]); const total = ref(0); const selectedId = ref<number | null>(null); const members = ref<TeamMemberItem[]>([]); const apps = ref<ApplicationItem[]>([]); const grantedModels = ref<string[]>([]); const allModels = ref<string[]>([]); const loading = ref(false); const dialog = ref<"team" | "limits" | "member" | "application" | "models" | null>(null);
const filters = reactive({ keyword: "", enabled: "", logicalModel: "", page: 0, size: 10 }); const selected = computed(() => teams.value.find(team => team.teamId === selectedId.value) ?? null);
const teamForm = reactive({ organizationId: 1, name: "", ownerName: "", ownerEmail: "", keyRpm: 60, teamRpm: 600, teamConcurrency: 20, modelConcurrency: 50 }); const limitForm = reactive({ keyRpm: 60, teamRpm: 600, teamConcurrency: 20, modelConcurrency: 50, enabled: true }); const memberForm = reactive({ name: "", email: "" }); const appForm = reactive({ name: "" }); const modelForm = ref<string[]>([]);
async function load(reset = false) { if (reset) filters.page = 0; loading.value = true; try { const [teamData, modelData] = await Promise.all([api.teams({ ...filters, enabled: filters.enabled || null, ownerUserId: props.ownerUserId ?? null }), api.directModels()]); teams.value = teamData.items; total.value = teamData.total; allModels.value = modelData.items.map(item => item.modelName); const preferredId = teams.value.some(team => team.teamId === selectedId.value) ? selectedId.value : teams.value[0]?.teamId; if (preferredId) await select(preferredId); else { selectedId.value = null; members.value = []; apps.value = []; grantedModels.value = []; } } catch (e) { ElMessage.error(e instanceof Error ? e.message : "团队列表加载失败"); } finally { loading.value = false; } }
function clear() { Object.assign(filters, { keyword: "", enabled: "", logicalModel: "", page: 0 }); void load(); }
async function select(id: number) { selectedId.value = id; const [memberData, appData, access] = await Promise.all([api.members(id), api.applications(id), api.teamModels(id)]); members.value = memberData.items; apps.value = appData.items; grantedModels.value = access.logicalModels; }
function openLimits() { if (!selected.value) return; Object.assign(limitForm, selected.value); dialog.value = "limits"; }
async function saveTeam() { try { await api.createTeam(teamForm); dialog.value = null; await load(); ElMessage.success("团队已创建"); } catch (e) { ElMessage.error(e instanceof Error ? e.message : "创建失败"); } }
async function saveLimits() { if (!selected.value) return; try { await api.updateTeam(selected.value.teamId, limitForm); dialog.value = null; await load(); ElMessage.success("团队限制已更新"); } catch (e) { ElMessage.error(e instanceof Error ? e.message : "更新失败"); } }
async function saveMember() { if (!selected.value) return; try { await api.createMember(selected.value.teamId, memberForm); dialog.value = null; Object.assign(memberForm, { name: "", email: "" }); await select(selected.value.teamId); } catch (e) { ElMessage.error(e instanceof Error ? e.message : "添加失败"); } }
async function saveApplication() { if (!selected.value) return; try { await api.createApplication(selected.value.teamId, appForm); dialog.value = null; appForm.name = ""; await select(selected.value.teamId); } catch (e) { ElMessage.error(e instanceof Error ? e.message : "添加失败"); } }
async function saveModels() { if (!selected.value) return; try { const access = await api.updateTeamModels(selected.value.teamId, modelForm.value); grantedModels.value = access.logicalModels; dialog.value = null; ElMessage.success("模型授权已更新"); } catch (e) { ElMessage.error(e instanceof Error ? e.message : "更新失败"); } }
function openModels() { modelForm.value = [...grantedModels.value]; dialog.value = "models"; }
async function removeTeam() { if (!selected.value) return; try { await ElMessageBox.confirm(`删除 ${selected.value.name} 前会检查成员、应用、Key、调用和额度账本依赖。`, "确认删除团队", { type: "warning" }); await api.deleteTeam(selected.value.teamId); ElMessage.success("团队已删除"); selectedId.value = null; await load(); } catch (e) { if (e !== "cancel" && e !== "close") ElMessage.error(e instanceof Error ? e.message : "删除失败"); } }
watch(() => [props.ownerUserId, props.adminMode], () => { void load(); }); onMounted(load);
</script>
<template><section class="page-stack" v-loading="loading"><header class="page-heading"><div><p class="eyebrow">Organization access boundary</p><h1>{{ adminMode ? '企业团队' : '我的团队' }}</h1><p>{{ adminMode ? '从列表选择团队，在右侧管理成员、应用、模型与网关限制。' : '只展示当前负责人所属团队，不会加载其他团队。' }}</p></div><el-button v-if="adminMode" type="primary" @click="dialog = 'team'">新增团队</el-button></header><section class="team-master"><aside class="surface team-list"><el-form class="search-stack" @submit.prevent="load(true)"><el-input v-model="filters.keyword" placeholder="搜索团队" clearable/><el-select v-model="filters.enabled" placeholder="状态" clearable><el-option label="启用" value="true"/><el-option label="停用" value="false"/></el-select><el-select v-model="filters.logicalModel" placeholder="已授权模型" clearable><el-option v-for="model in allModels" :key="model" :label="model" :value="model"/></el-select><div><el-button type="primary" native-type="submit">搜索</el-button><el-button @click="clear">重置</el-button></div></el-form><div class="compact-list"><button v-for="team in teams" :key="team.teamId" class="list-row" :class="{ selected: team.teamId === selectedId }" @click="select(team.teamId)"><strong>{{ team.name }}</strong><small>{{ team.memberCount }} 成员 · {{ team.keyCount }} 个 Key</small></button></div><el-pagination v-if="adminMode" small layout="prev, pager, next" :total="total" :page-size="filters.size" :current-page="filters.page + 1" @current-change="page => { filters.page = page - 1; load(); }"/></aside><section v-if="selected" class="surface team-detail"><div class="section-title"><div><p class="eyebrow">Team detail</p><h2>{{ selected.name }}</h2><p class="muted">负责人 {{ selected.ownerName || '-' }} · {{ selected.ownerEmail || '-' }}</p></div><div><el-tag :type="selected.enabled ? 'success' : 'info'">{{ selected.enabled ? '启用' : '停用' }}</el-tag><el-button text @click="openLimits">编辑限制</el-button><el-button v-if="adminMode" text type="danger" @click="removeTeam">删除团队</el-button></div></div><div class="detail-metrics"><span>Key RPM<strong>{{ selected.keyRpm }}</strong></span><span>团队 RPM<strong>{{ selected.teamRpm }}</strong></span><span>团队并发<strong>{{ selected.teamConcurrency }}</strong></span><span>模型并发<strong>{{ selected.modelConcurrency }}</strong></span></div><div class="detail-block"><div class="section-title"><h3>模型授权</h3><el-button text type="primary" @click="openModels">调整授权</el-button></div><el-tag v-for="model in grantedModels" :key="model" class="app-tag">{{ model }}</el-tag><p v-if="!grantedModels.length" class="muted">尚未授权模型。</p></div><div class="detail-block"><div class="section-title"><h3>应用</h3><el-button text type="primary" @click="dialog = 'application'">新增应用</el-button></div><el-table :data="apps" size="small"><el-table-column prop="name" label="应用"/><el-table-column prop="createdAt" label="创建时间"/></el-table></div><div class="detail-block"><div class="section-title"><h3>成员</h3><el-button v-if="adminMode" text type="primary" @click="dialog = 'member'">新增成员</el-button></div><el-table :data="members" size="small"><el-table-column prop="name" label="姓名"/><el-table-column prop="email" label="邮箱"/><el-table-column prop="role" label="角色"/><el-table-column label="状态"><template #default="scope"><el-tag :type="scope.row.enabled ? 'success' : 'info'">{{ scope.row.enabled ? '启用' : '停用' }}</el-tag></template></el-table-column></el-table></div></section><section v-else class="surface empty-state"><h2>{{ adminMode ? '选择一个团队' : '该负责人尚未分配团队' }}</h2><p>{{ adminMode ? '从左侧列表选择团队后查看详情。' : '请在用户管理中为该负责人分配团队。' }}</p></section></section><el-dialog v-model="dialog" :title="dialog === 'team' ? '新增团队' : dialog === 'limits' ? '编辑网关限制' : dialog === 'member' ? '新增成员' : dialog === 'application' ? '新增应用' : '调整模型授权'" width="520px"><el-form v-if="dialog === 'team'" label-position="top"><el-form-item label="团队名称"><el-input v-model="teamForm.name"/></el-form-item><el-form-item label="负责人"><el-input v-model="teamForm.ownerName"/></el-form-item><el-form-item label="负责人邮箱"><el-input v-model="teamForm.ownerEmail"/></el-form-item></el-form><el-form v-else-if="dialog === 'limits'" label-position="top"><el-form-item label="Key RPM"><el-input-number v-model="limitForm.keyRpm" :min="1"/></el-form-item><el-form-item label="团队 RPM"><el-input-number v-model="limitForm.teamRpm" :min="1"/></el-form-item><el-form-item label="团队并发"><el-input-number v-model="limitForm.teamConcurrency" :min="1"/></el-form-item><el-form-item label="模型并发"><el-input-number v-model="limitForm.modelConcurrency" :min="1"/></el-form-item></el-form><el-form v-else-if="dialog === 'member'" label-position="top"><el-form-item label="姓名"><el-input v-model="memberForm.name"/></el-form-item><el-form-item label="邮箱"><el-input v-model="memberForm.email"/></el-form-item></el-form><el-form v-else-if="dialog === 'application'" label-position="top"><el-form-item label="应用名称"><el-input v-model="appForm.name"/></el-form-item></el-form><el-checkbox-group v-else v-model="modelForm" class="checkbox-stack"><el-checkbox v-for="model in allModels" :key="model" :label="model">{{ model }}</el-checkbox></el-checkbox-group><template #footer><el-button @click="dialog = null">取消</el-button><el-button type="primary" @click="dialog === 'team' ? saveTeam() : dialog === 'limits' ? saveLimits() : dialog === 'member' ? saveMember() : dialog === 'application' ? saveApplication() : saveModels()">保存</el-button></template></el-dialog></section></template>
